    /* =======================
    CREAR PERSONALIZADA
  ======================= */ async function createCustomTemplate() {
        if (!canCreateCustom) {
            alert("Debes completar todos los campos para crear la plantilla personalizada.");
            return;
        }
        setCreatingCustom(true);
        try {
            const res = await fetch("/api/plantillas-personalizadas", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({
                    cuenta_bancaria: "0000000000",
                    subproducto: nombrePlantilla,
                    url: "/plantillas/custom/default.png",
                    tipo: "personalizada",
                    visual: "no"
                })
            });
            const plantilla = await res.json();
            if (!res.ok) {
                throw new Error(plantilla?.error || "No se pudo crear la plantilla");
            }
            const resConfig = await fetch("/api/plantillas-personalizadas/config", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({
                    plantilla_id: plantilla.id,
                    ...config
                })
            });
            const configJson = await resConfig.json().catch(()=>({}));
            if (!resConfig.ok) {
                throw new Error(configJson?.error || "No se pudo guardar la configuración");
            }
            setNombrePlantilla("");
            setConfig({
                subproducto_lista_id: "",
                liga_pago_lista_id: "",
                metodo_pago_lista_id: "",
                producto_lista_id: ""
            });
            load();
        } catch (error) {
            console.error("❌ Error creando plantilla personalizada:", error);
            alert(error instanceof Error ? error.message : "Error creando plantilla personalizada");
        } finally{
            setCreatingCustom(false);
        }
    }
    /* =======================
    TOGGLE VISUAL
  ======================= */ async function toggleVisual(id, actual) {
        await fetch(`/api/plantillas/${id}`, {
            method: "PATCH",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({
                visual: actual === "si" ? "no" : "si"
            })
        });
        load();
    }
    /* =======================
    ELIMINAR
  ======================= */ async function deleteTemplate(id) {
        if (!confirm("¿Eliminar plantilla?")) return;
        await fetch(`/api/plantillas/${id}`, {
            method: "DELETE"
        });
        load();
    }
